  "reader.articles.newsfeed-2018-02-19-ambrite-presentation": {
    "key": "reader.articles.newsfeed-2018-02-19-ambrite-presentation",
    "appId": "reader",
    "subroute": "articles/newsfeed-2018-02-19-ambrite-presentation",
    "title": "Ambrite AI Presentation",
    "excerpt": "Representatives from Ambrite will be giving a presentation aimed at the CS315/AM796 class on 19 February.",
    "shell": "default",
    "meta": {
      "sort_order": "111",
      "card_badge": "Newsfeed"
    },
    "html": "<div class=\"newsitem\"><h1>Ambrite AI Presentation</h1><div class=\"newsdate\"><span class=\"day\"> Monday </span><span class=\"date\"> 19 </span><span class=\"month\">February</span><span class=\"year\">2018</span></div><p>Representatives from Ambrite will be giving a presentation aimed at the CS315/AM796 class on 19 February.</p><p>Ambrite (http://www.ambrite.ch/) is a Swiss, Latvian and South African based company offering software solutions in applied machine learning and data science. They are currently developing products for the entertainment industry, combining IT and AI (anomaly detection, natural language processing, next generation user interfaces). For their Stellenbosch-based branch, they are looking for machine intelligence engineers, data scientists and full-stack developers with an interest in machine learning. Representatives from Ambrite will be giving a presentation aimed at the CS315/AM796 class at 4PM on Monday, during the tutorial session in NARGA A. Afterwards, you can also join them for further discussion of what they do and the challenges they face at an open event advertised on the Maties Machine Learning (MML) group at 17:30 on Monday in the Knowledge Centre K303.</p></div>\n\n",
    "sections": [
      {
        "key": "000-main-inline-1",
        "slot": "main",
        "html": "<div class=\"newsitem\"><h1>Ambrite AI Presentation</h1><div class=\"newsdate\"><span class=\"day\"> Monday </span><span class=\"date\"> 19 </span><span class=\"month\">February</span><span class=\"year\">2018</span></div><p>Representatives from Ambrite will be giving a presentation aimed at the CS315/AM796 class on 19 February.</p><p>Ambrite (http://www.ambrite.ch/) is a Swiss, Latvian and South African based company offering software solutions in applied machine learning and data science. They are currently developing products for the entertainment industry, combining IT and AI (anomaly detection, natural language processing, next generation user interfaces). For their Stellenbosch-based branch, they are looking for machine intelligence engineers, data scientists and full-stack developers with an interest in machine learning. Representatives from Ambrite will be giving a presentation aimed at the CS315/AM796 class at 4PM on Monday, during the tutorial session in NARGA A. Afterwards, you can also join them for further discussion of what they do and the challenges they face at an open event advertised on the Maties Machine Learning (MML) group at 17:30 on Monday in the Knowledge Centre K303.</p></div>\n\n"
      }
    ]
  },
