  "reader.articles.why-this-site": {
    "key": "reader.articles.why-this-site",
    "appId": "reader",
    "subroute": "articles/why-this-site",
    "title": "Why This Site",
    "excerpt": "Why we chose an OS-style web architecture for department content.",
    "shell": "default",
    "meta": {
      "sort_order": "1",
      "card_title": "Why This Site",
      "card_excerpt": "A quick, hands-on tour of why this site is built like a lightweight web workspace.",
      "card_badge": "Editorial",
      "card_variant": "feature"
    },
    "html": "<h2>Why This Site</h2>\n<p>Short version: this site lets you keep your browser habits and still get a faster in-site workflow.</p>\n<ul>\n<li>Keep normal browser tabs, back/forward, and shareable URLs.</li>\n<li>Add app windows that stay alive while you navigate.</li>\n<li>Keep content simple with markdown, while interface behavior stays programmable.</li>\n</ul>\n<p>If you want the pitch, that is it.\nIf you want proof, run the guided mission:</p>\n<h3>Start The Guided Mission</h3>\n<p><a href=\"/demo\">Open Demo Mission</a></p>\n<p>It takes a few clicks and shows the model better than a long explanation.</p>\n",
    "sections": [
      {
        "key": "000-main-inline-1",
        "slot": "main",
        "html": "<h2>Why This Site</h2>\n<p>Short version: this site lets you keep your browser habits and still get a faster in-site workflow.</p>\n<ul>\n<li>Keep normal browser tabs, back/forward, and shareable URLs.</li>\n<li>Add app windows that stay alive while you navigate.</li>\n<li>Keep content simple with markdown, while interface behavior stays programmable.</li>\n</ul>\n<p>If you want the pitch, that is it.\nIf you want proof, run the guided mission:</p>\n<h3>Start The Guided Mission</h3>\n<p><a href=\"/demo\">Open Demo Mission</a></p>\n<p>It takes a few clicks and shows the model better than a long explanation.</p>\n"
      }
    ]
  },
  "reader.general.help": {
    "key": "reader.general.help",
    "appId": "reader",
    "subroute": "general/help",
    "title": "Help",
    "excerpt": "Quick help for navigating this site.",
    "shell": "default",
    "meta": {},
    "html": "<h2>Help</h2>\n<p>This website works like a browser-based desktop workspace.</p>\n<h3>Quick Start</h3>\n<ul>\n<li>Open <strong>Home</strong> for the landing page.</li>\n<li>Open <strong>Articles</strong> for news and updates.</li>\n<li>Open <strong>People / Programs / Research / About</strong> from <strong>Applications</strong>.</li>\n</ul>\n<h3>Window Basics</h3>\n<ul>\n<li>The URL decides which app and content route is active.</li>\n<li>Apps stay open until you close their window.</li>\n<li>Sidebar entries represent open windows across tabs.</li>\n<li>Click a sidebar entry to focus it.</li>\n<li>Click the focused sidebar entry to minimize it.</li>\n</ul>\n<h3>Desktop vs Phone Controls</h3>\n<ul>\n<li>Desktop: right-click a link for <strong>Open in New App Window</strong> or <strong>Open in New Browser Tab</strong>.</li>\n<li>Phone: tap and hold a link for the same options.</li>\n<li>Phone: use the bottom bar <strong>Tabs</strong> button to switch windows.</li>\n</ul>\n<h3>Interactive Demo</h3>\n<p>Try the built-in demo flow:</p>\n<ul>\n<li><a href=\"/demo\">Start Demo</a></li>\n</ul>\n<h3>Need Help Quickly?</h3>\n<ul>\n<li>Right-click (or tap and hold) anywhere and choose <strong>Help</strong> to return here.</li>\n</ul>\n<p>If you are new here, start on Home and open articles from the landing page cards.</p>\n",
    "sections": [
      {
        "key": "000-main-inline-1",
        "slot": "main",
        "html": "<h2>Help</h2>\n<p>This website works like a browser-based desktop workspace.</p>\n<h3>Quick Start</h3>\n<ul>\n<li>Open <strong>Home</strong> for the landing page.</li>\n<li>Open <strong>Articles</strong> for news and updates.</li>\n<li>Open <strong>People / Programs / Research / About</strong> from <strong>Applications</strong>.</li>\n</ul>\n<h3>Window Basics</h3>\n<ul>\n<li>The URL decides which app and content route is active.</li>\n<li>Apps stay open until you close their window.</li>\n<li>Sidebar entries represent open windows across tabs.</li>\n<li>Click a sidebar entry to focus it.</li>\n<li>Click the focused sidebar entry to minimize it.</li>\n</ul>\n<h3>Desktop vs Phone Controls</h3>\n<ul>\n<li>Desktop: right-click a link for <strong>Open in New App Window</strong> or <strong>Open in New Browser Tab</strong>.</li>\n<li>Phone: tap and hold a link for the same options.</li>\n<li>Phone: use the bottom bar <strong>Tabs</strong> button to switch windows.</li>\n</ul>\n<h3>Interactive Demo</h3>\n<p>Try the built-in demo flow:</p>\n<ul>\n<li><a href=\"/demo\">Start Demo</a></li>\n</ul>\n<h3>Need Help Quickly?</h3>\n<ul>\n<li>Right-click (or tap and hold) anywhere and choose <strong>Help</strong> to return here.</li>\n</ul>\n<p>If you are new here, start on Home and open articles from the landing page cards.</p>\n"
      }
    ]
  },
