  "tw314.coding_error": {
    "key": "tw314.coding_error",
    "appId": "tw314",
    "subroute": "coding_error",
    "title": "Error-correcting codes",
    "excerpt": "",
    "shell": "tw314-native",
    "meta": {
      "sort_order": "43"
    },
    "html": "<div class=\"tw314-native-document\" data-tw314-slug=\"coding_error\">\n<div id=\"content\" class=\"pretext-content\"><section class=\"chapter\" id=\"coding_error\"><h2 class=\"heading\">\n<span class=\"type\">Chapter</span> <span class=\"codenumber\">8</span> <span class=\"title\">Error-correcting codes</span>\n</h2>\n<section class=\"introduction\" id=\"introduction-8\"><p id=\"p-465\">In this chapter we discuss some basic ideas in coding theory. We look at block codes, error-correcting, Hamming distances and perfect codes.</p></section><nav class=\"summary-links\"><ul>\n<li><a href=\"/tw314/section-coding-intro\"><span class=\"codenumber\">8.1</span> <span class=\"title\">Introduction</span></a></li>\n<li><a href=\"/tw314/section-coding-channel\"><span class=\"codenumber\">8.2</span> <span class=\"title\">A digital communication system</span></a></li>\n<li><a href=\"/tw314/section-coding-block\"><span class=\"codenumber\">8.3</span> <span class=\"title\">Block codes</span></a></li>\n<li><a href=\"/tw314/section-coding-hamming\"><span class=\"codenumber\">8.4</span> <span class=\"title\">Hamming distances</span></a></li>\n<li><a href=\"/tw314/section-coding-neighbour\"><span class=\"codenumber\">8.5</span> <span class=\"title\">Nearest neighbour decoding</span></a></li>\n<li><a href=\"/tw314/section-coding-minimum\"><span class=\"codenumber\">8.6</span> <span class=\"title\">Minimum distance</span></a></li>\n<li><a href=\"/tw314/section-coding-equiv\"><span class=\"codenumber\">8.7</span> <span class=\"title\">Equivalent codes</span></a></li>\n<li><a href=\"/tw314/section-coding-parameters\"><span class=\"codenumber\">8.8</span> <span class=\"title\">Optimising the parameters \\(n\\text{,}\\) \\(M\\) and \\(d\\)</span></a></li>\n<li><a href=\"/tw314/section-coding-hammingbound\"><span class=\"codenumber\">8.9</span> <span class=\"title\">The Hamming bound</span></a></li>\n<li><a href=\"/tw314/section-coding-perfect\"><span class=\"codenumber\">8.10</span> <span class=\"title\">Perfect codes</span></a></li>\n</ul></nav></section></div>\n</div>\n\n",
    "sections": [
      {
        "key": "000-main-inline-1",
        "slot": "main",
        "html": "<div class=\"tw314-native-document\" data-tw314-slug=\"coding_error\">\n<div id=\"content\" class=\"pretext-content\"><section class=\"chapter\" id=\"coding_error\"><h2 class=\"heading\">\n<span class=\"type\">Chapter</span> <span class=\"codenumber\">8</span> <span class=\"title\">Error-correcting codes</span>\n</h2>\n<section class=\"introduction\" id=\"introduction-8\"><p id=\"p-465\">In this chapter we discuss some basic ideas in coding theory. We look at block codes, error-correcting, Hamming distances and perfect codes.</p></section><nav class=\"summary-links\"><ul>\n<li><a href=\"/tw314/section-coding-intro\"><span class=\"codenumber\">8.1</span> <span class=\"title\">Introduction</span></a></li>\n<li><a href=\"/tw314/section-coding-channel\"><span class=\"codenumber\">8.2</span> <span class=\"title\">A digital communication system</span></a></li>\n<li><a href=\"/tw314/section-coding-block\"><span class=\"codenumber\">8.3</span> <span class=\"title\">Block codes</span></a></li>\n<li><a href=\"/tw314/section-coding-hamming\"><span class=\"codenumber\">8.4</span> <span class=\"title\">Hamming distances</span></a></li>\n<li><a href=\"/tw314/section-coding-neighbour\"><span class=\"codenumber\">8.5</span> <span class=\"title\">Nearest neighbour decoding</span></a></li>\n<li><a href=\"/tw314/section-coding-minimum\"><span class=\"codenumber\">8.6</span> <span class=\"title\">Minimum distance</span></a></li>\n<li><a href=\"/tw314/section-coding-equiv\"><span class=\"codenumber\">8.7</span> <span class=\"title\">Equivalent codes</span></a></li>\n<li><a href=\"/tw314/section-coding-parameters\"><span class=\"codenumber\">8.8</span> <span class=\"title\">Optimising the parameters \\(n\\text{,}\\) \\(M\\) and \\(d\\)</span></a></li>\n<li><a href=\"/tw314/section-coding-hammingbound\"><span class=\"codenumber\">8.9</span> <span class=\"title\">The Hamming bound</span></a></li>\n<li><a href=\"/tw314/section-coding-perfect\"><span class=\"codenumber\">8.10</span> <span class=\"title\">Perfect codes</span></a></li>\n</ul></nav></section></div>\n</div>\n\n"
      }
    ]
  },
