    "html": "<div class=\"tw314-native-document\" data-tw314-slug=\"coding_hamming\">\n<div id=\"content\" class=\"pretext-content\"><section class=\"chapter\" id=\"coding_hamming\"><h2 class=\"heading\">\n<span class=\"type\">Chapter</span> <span class=\"codenumber\">10</span> <span class=\"title\">Hamming codes</span>\n</h2>\n<section class=\"introduction\" id=\"introduction-10\"><p id=\"p-591\">In this chapter we consider a family of single-error-correcting linear codes called Hamming codes.</p></section><nav class=\"summary-links\"><ul>\n<li><a href=\"/tw314/section-coding-ham-intro\"><span class=\"codenumber\">10.1</span> <span class=\"title\">Introduction</span></a></li>\n<li><a href=\"/tw314/section-coding-ham-decode\"><span class=\"codenumber\">10.2</span> <span class=\"title\">Decoding with a binary Hamming code</span></a></li>\n<li><a href=\"/tw314/section-coding-ham-extend\"><span class=\"codenumber\">10.3</span> <span class=\"title\">The extended binary Hamming code</span></a></li>\n<li><a href=\"/tw314/section-coding-fund\"><span class=\"codenumber\">10.4</span> <span class=\"title\">A fundamental theorem</span></a></li>\n<li><a href=\"/tw314/section-coding-qham\"><span class=\"codenumber\">10.5</span> <span class=\"title\">\\(q\\)-ary Hamming codes</span></a></li>\n<li><a href=\"/tw314/section-coding-qham-decode\"><span class=\"codenumber\">10.6</span> <span class=\"title\">Decoding with a \\(q\\)-ary Hamming code</span></a></li>\n</ul></nav></section></div>\n</div>\n\n",
    "sections": [
      {
        "key": "000-main-inline-1",
        "slot": "main",
        "html": "<div class=\"tw314-native-document\" data-tw314-slug=\"coding_hamming\">\n<div id=\"content\" class=\"pretext-content\"><section class=\"chapter\" id=\"coding_hamming\"><h2 class=\"heading\">\n<span class=\"type\">Chapter</span> <span class=\"codenumber\">10</span> <span class=\"title\">Hamming codes</span>\n</h2>\n<section class=\"introduction\" id=\"introduction-10\"><p id=\"p-591\">In this chapter we consider a family of single-error-correcting linear codes called Hamming codes.</p></section><nav class=\"summary-links\"><ul>\n<li><a href=\"/tw314/section-coding-ham-intro\"><span class=\"codenumber\">10.1</span> <span class=\"title\">Introduction</span></a></li>\n<li><a href=\"/tw314/section-coding-ham-decode\"><span class=\"codenumber\">10.2</span> <span class=\"title\">Decoding with a binary Hamming code</span></a></li>\n<li><a href=\"/tw314/section-coding-ham-extend\"><span class=\"codenumber\">10.3</span> <span class=\"title\">The extended binary Hamming code</span></a></li>\n<li><a href=\"/tw314/section-coding-fund\"><span class=\"codenumber\">10.4</span> <span class=\"title\">A fundamental theorem</span></a></li>\n<li><a href=\"/tw314/section-coding-qham\"><span class=\"codenumber\">10.5</span> <span class=\"title\">\\(q\\)-ary Hamming codes</span></a></li>\n<li><a href=\"/tw314/section-coding-qham-decode\"><span class=\"codenumber\">10.6</span> <span class=\"title\">Decoding with a \\(q\\)-ary Hamming code</span></a></li>\n</ul></nav></section></div>\n</div>\n\n"
      }
    ]
