    "html": "<div class=\"tw314-native-document\" data-tw314-slug=\"part-graph\">\n<div id=\"content\" class=\"pretext-content\"><section class=\"part\" id=\"part-graph\"><h2 class=\"heading hide-type\">\n<span class=\"type\">Part</span> <span class=\"codenumber\">I</span> <span class=\"title\">Graph Theory</span>\n</h2>\n<nav class=\"summary-links\"><ul>\n<li><a href=\"/tw314/graphs\"><span class=\"codenumber\">1</span> <span class=\"title\">An introduction to graphs</span></a></li>\n<li><a href=\"/tw314/planar\"><span class=\"codenumber\">2</span> <span class=\"title\">Planar graphs</span></a></li>\n<li><a href=\"/tw314/colour\"><span class=\"codenumber\">3</span> <span class=\"title\">Graph colourings</span></a></li>\n</ul></nav></section></div>\n</div>\n\n",
